package policies

import (
	"github.com/nginx/nginx-gateway-fabric/v2/internal/controller/nginx/config/http"
)

// Generator defines an interface for a policy to implement its appropriate generator functions.
//
//counterfeiter:generate . Generator
type Generator interface {
	// GenerateForMain generates policy configuration for the main block.
	GenerateForMain(policies []Policy) GenerateResultFiles
	// GenerateForHTTP generates policy configuration for the http block.
	GenerateForHTTP(policies []Policy) GenerateResultFiles
	// GenerateForServer generates policy configuration for the server block.
	GenerateForServer(policies []Policy, server http.Server) GenerateResultFiles
	// GenerateForLocation generates policy configuration for a normal location block.
	GenerateForLocation(policies []Policy, location http.Location) GenerateResultFiles
	// GenerateForInternalLocation generates policy configuration for an internal location block.
	GenerateForInternalLocation(policies []Policy) GenerateResultFiles
}

// GenerateResultFiles is a list of files generated for inclusion by policy generators.
type GenerateResultFiles []File

// File is the contents of the generated file.
type File struct {
	Name    string
	Content []byte
}

// CompositeGenerator contains all policy generators.
type CompositeGenerator struct {
	generators []Generator
}

// NewCompositeGenerator returns a new instance of a CompositeGenerator.
func NewCompositeGenerator(generators ...Generator) *CompositeGenerator {
	return &CompositeGenerator{generators: generators}
}

// GenerateForMain calls all policy generators for the main block.
func (g *CompositeGenerator) GenerateForMain(policies []Policy) GenerateResultFiles {
	var compositeResult GenerateResultFiles

	for _, generator := range g.generators {
		compositeResult = append(compositeResult, generator.GenerateForMain(policies)...)
	}

	return compositeResult
}

// GenerateForHTTP calls all policy generators for the http block.
func (g *CompositeGenerator) GenerateForHTTP(policies []Policy) GenerateResultFiles {
	var compositeResult GenerateResultFiles

	for _, generator := range g.generators {
		compositeResult = append(compositeResult, generator.GenerateForHTTP(policies)...)
	}

	return compositeResult
}

// GenerateForServer calls all policy generators for the server block.
func (g *CompositeGenerator) GenerateForServer(policies []Policy, server http.Server) GenerateResultFiles {
	var compositeResult GenerateResultFiles

	for _, generator := range g.generators {
		compositeResult = append(compositeResult, generator.GenerateForServer(policies, server)...)
	}

	return compositeResult
}

// GenerateForLocation calls all policy generators for a normal location block.
func (g *CompositeGenerator) GenerateForLocation(policies []Policy, location http.Location) GenerateResultFiles {
	var compositeResult GenerateResultFiles

	for _, generator := range g.generators {
		compositeResult = append(compositeResult, generator.GenerateForLocation(policies, location)...)
	}

	return compositeResult
}

// GenerateForInternalLocation calls all policy generators for an internal location block.
func (g *CompositeGenerator) GenerateForInternalLocation(policies []Policy) GenerateResultFiles {
	var compositeResult GenerateResultFiles

	for _, generator := range g.generators {
		compositeResult = append(compositeResult, generator.GenerateForInternalLocation(policies)...)
	}

	return compositeResult
}

// UnimplementedGenerator can be inherited by any policy generator that may not need to implement all of
// possible generations, in order to satisfy the Generator interface.
type UnimplementedGenerator struct{}

func (u UnimplementedGenerator) GenerateForMain(_ []Policy) GenerateResultFiles {
	return nil
}

func (u UnimplementedGenerator) GenerateForHTTP(_ []Policy) GenerateResultFiles {
	return nil
}

func (u UnimplementedGenerator) GenerateForServer(_ []Policy, _ http.Server) GenerateResultFiles {
	return nil
}

func (u UnimplementedGenerator) GenerateForLocation(_ []Policy, _ http.Location) GenerateResultFiles {
	return nil
}

func (u UnimplementedGenerator) GenerateForInternalLocation(_ []Policy) GenerateResultFiles {
	return nil
}

package policies

//go:generate go tool counterfeiter -generate

import (
	"fmt"

	"k8s.io/apimachinery/pkg/runtime/schema"

	"github.com/nginx/nginx-gateway-fabric/v2/internal/controller/state/conditions"
	"github.com/nginx/nginx-gateway-fabric/v2/internal/framework/kinds"
)

// Validator validates an NGF Policy.
//
//counterfeiter:generate . Validator
type Validator interface {
	// Validate validates an NGF Policy.
	Validate(policy Policy) []conditions.Condition
	// ValidateGlobalSettings validates an NGF Policy with the NginxProxy settings.
	ValidateGlobalSettings(policy Policy, globalSettings *GlobalSettings) []conditions.Condition
	// Conflicts returns true if the two Policies conflict.
	Conflicts(a, b Policy) bool
}

// CompositeValidator manages the validators for NGF Policies.
type CompositeValidator struct {
	validators     map[schema.GroupVersionKind]Validator
	mustExtractGVK kinds.MustExtractGVK
}

// ManagerConfig contains the config to register a Policy with the CompositeValidator.
type ManagerConfig struct {
	// Validator is the Validator for the Policy.
	Validator Validator
	// GVK is the GroupVersionKind of the Policy.
	GVK schema.GroupVersionKind
}

// NewManager returns a new CompositeValidator.
// Implements validation.PolicyValidator.
func NewManager(
	mustExtractGVK kinds.MustExtractGVK,
	configs ...ManagerConfig,
) *CompositeValidator {
	v := &CompositeValidator{
		validators:     make(map[schema.GroupVersionKind]Validator),
		mustExtractGVK: mustExtractGVK,
	}

	for _, cfg := range configs {
		v.validators[cfg.GVK] = cfg.Validator
	}

	return v
}

// Validate validates the policy.
func (m *CompositeValidator) Validate(policy Policy) []conditions.Condition {
	gvk := m.mustExtractGVK(policy)

	validator, ok := m.validators[gvk]
	if !ok {
		panic(fmt.Sprintf("no validator registered for policy %T", policy))
	}

	return validator.Validate(policy)
}

// ValidateGlobalSettings validates an NGF Policy with the NginxProxy settings.
func (m *CompositeValidator) ValidateGlobalSettings(
	policy Policy,
	globalSettings *GlobalSettings,
) []conditions.Condition {
	gvk := m.mustExtractGVK(policy)

	validator, ok := m.validators[gvk]
	if !ok {
		panic(fmt.Sprintf("no validator registered for policy %T", policy))
	}

	return validator.ValidateGlobalSettings(policy, globalSettings)
}

// Conflicts returns true if the policies conflict.
func (m *CompositeValidator) Conflicts(polA, polB Policy) bool {
	gvk := m.mustExtractGVK(polA)

	validator, ok := m.validators[gvk]
	if !ok {
		panic(fmt.Sprintf("no validator registered for policy %T", polA))
	}

	return validator.Conflicts(polA, polB)
}

package policies

import (
	"slices"

	"k8s.io/apimachinery/pkg/util/validation/field"
	"sigs.k8s.io/controller-runtime/pkg/client"
	gatewayv1 "sigs.k8s.io/gateway-api/apis/v1"
)

//go:generate go tool counterfeiter -generate

// Policy is an extension of client.Object. It adds methods that are common among all NGF Policies.
//
//counterfeiter:generate . Policy
type Policy interface {
	GetTargetRefs() []gatewayv1.LocalPolicyTargetReference
	GetPolicyStatus() gatewayv1.PolicyStatus
	SetPolicyStatus(status gatewayv1.PolicyStatus)
	client.Object
}

// GlobalSettings contains global settings from the current state of the graph that may be
// needed for policy validation or generation if certain policies rely on those global settings.
type GlobalSettings struct {
	// TelemetryEnabled is whether telemetry is enabled in the NginxProxy resource.
	TelemetryEnabled bool
	// WAFEnabled is whether WAF is enabled in the NginxProxy resource.
	WAFEnabled bool
}

// ValidateTargetRef validates a policy's targetRef for the proper group and kind.
func ValidateTargetRef(
	ref gatewayv1.LocalPolicyTargetReference,
	basePath *field.Path,
	groups []gatewayv1.Group,
	supportedKinds []gatewayv1.Kind,
) error {
	if !slices.Contains(groups, ref.Group) {
		path := basePath.Child("group")

		return field.NotSupported(
			path,
			ref.Group,
			groups,
		)
	}

	if !slices.Contains(supportedKinds, ref.Kind) {
		path := basePath.Child("kind")

		return field.NotSupported(
			path,
			ref.Kind,
			supportedKinds,
		)
	}

	return nil
}

// We generate a mock of ObjectKind so that we can create fake policies and set their GVKs.
//counterfeiter:generate k8s.io/apimachinery/pkg/runtime/schema.ObjectKind

