1	package ratelimit
2	
3	import (
4		"fmt"
5		"text/template"
6	
7		ngfAPI "github.com/nginx/nginx-gateway-fabric/v2/apis/v1alpha1"
8		"github.com/nginx/nginx-gateway-fabric/v2/internal/controller/nginx/config/http"
9		"github.com/nginx/nginx-gateway-fabric/v2/internal/controller/nginx/config/policies"
10		"github.com/nginx/nginx-gateway-fabric/v2/internal/controller/state/dataplane"
11		"github.com/nginx/nginx-gateway-fabric/v2/internal/framework/helpers"
12	)
13	
14	// rateLimitHTTPTemplate generates only the limit_req_zone directive at the http context.
15	const rateLimitHTTPTemplate = `
16	{{ range $r := .Rule }}
17	limit_req_zone {{ .Key }} zone={{ .ZoneName }}:{{ .ZoneSize }} rate={{ .Rate }};
18	{{ end }}
19	`
20	
21	//nolint:lll
22	const rateLimitReqTemplate = `
23	{{ range $r := .Rule }}
24	limit_req zone={{ .ZoneName }}{{ if .Burst }} burst={{ .Burst }}{{ end }}{{ if .NoDelay }} nodelay{{ end }}{{ if .Delay }} delay={{ .Delay }}{{ end }};
25	{{ end }}
26	{{- if .LogLevel }}
27	limit_req_log_level {{ .LogLevel }};
28	{{- end }}
29	{{- if .RejectCode }}
30	limit_req_status {{ .RejectCode }};
31	{{- end }}
32	{{- if .DryRun }}
33	limit_req_dry_run on;
34	{{- end }}
35	`
36	
37	var (
38		tmplHTTP     = template.Must(template.New("rate limit policy http").Parse(rateLimitHTTPTemplate))
39		tmplServer   = template.Must(template.New("rate limit policy server").Parse(rateLimitReqTemplate))
40		tmplLocation = template.Must(template.New("rate limit policy location").Parse(rateLimitReqTemplate))
41	)
42	
43	const (
44		// fileNamePrefix is the prefix for all generated rate limit policy config file names.
45		fileNamePrefix = "RateLimitPolicy"
46	
47		fileNameSuffixGateway  = "gateway"
48		fileNameSuffixHTTP     = "internal_http"
49		fileNameSuffixServer   = "gateway_server"
50		fileNameSuffixLocation = "route"
51	
52		// defaultZoneSize is the default size of the shared memory zone in the limit_req_zone NGINX directive.
53		defaultZoneSize = "10m"
54		// defaultRate is the default request rate in the limit_req_zone NGINX directive.
55		defaultRate = "100r/s"
56		// defaultKey is the default key in the limit_req_zone NGINX directive.
57		defaultKey = "$binary_remote_addr"
58	)
59	
60	// rateLimitSettings represents the settings for a rate limit policy.
61	type rateLimitSettings struct {
62		// LogLevel is the log level for cases when the server refuses to process requests due to
63		// rate exceeding, or delays request processing.
64		LogLevel string
65		// Rule is the list of rate limit rules.
66		Rule []rateLimitRule
67		// RejectCode is the status code to return in response to rejected requests.
68		RejectCode int
69		// DryRun enables the dry run mode, where the rate limit is not actually applied, but the number
70		// of excessive requests is accounted as usual in the shared memory zone.
71		DryRun bool
72	}
73	
74	// rateLimitRule represents a single rate limit rule.
75	type rateLimitRule struct {
76		// ZoneName is the name of the shared memory zone.
77		ZoneName string
78		// ZoneSize is the size of the shared memory zone.
79		ZoneSize string
80		// Rate is the request rate.
81		Rate string
82		// Key is the key to use for rate limiting.
83		Key string
84		// Delay is the delay for excessive requests.
85		Delay int
86		// Burst is the maximum number of excessive requests that can be delayed.
87		Burst int
88		// NoDelay indicates whether excessive requests are processed without delay.
89		NoDelay bool
90	}
91	
92	func getRateLimitSettings(rlp ngfAPI.RateLimitPolicy) rateLimitSettings {
93		settings := rateLimitSettings{}
94	
95		if rlp.Spec.RateLimit != nil {
96			if rlp.Spec.RateLimit.DryRun != nil {
97				settings.DryRun = *rlp.Spec.RateLimit.DryRun
98			}
99	
100			if rlp.Spec.RateLimit.LogLevel != nil {
101				settings.LogLevel = string(*rlp.Spec.RateLimit.LogLevel)
102			}
103	
104			if rlp.Spec.RateLimit.RejectCode != nil {
105				settings.RejectCode = int(*rlp.Spec.RateLimit.RejectCode)
106			}
107	
108			if rlp.Spec.RateLimit.Local != nil {
109				for i, rule := range rlp.Spec.RateLimit.Local.Rules {
110					rlRule := rateLimitRule{}
111	
112					rlRule.ZoneSize = defaultZoneSize
113					if rule.ZoneSize != nil {
114						rlRule.ZoneSize = string(*rule.ZoneSize)
115					}
116	
117					if rule.Delay != nil {
118						rlRule.Delay = int(*rule.Delay)
119					}
120	
121					if rule.Burst != nil {
122						rlRule.Burst = int(*rule.Burst)
123					}
124	
125					if rule.NoDelay != nil {
126						rlRule.NoDelay = *rule.NoDelay
127					}
128	
129					rlRule.Rate = defaultRate
130					if rule.Rate != "" {
131						rlRule.Rate = string(rule.Rate)
132					}
133	
134					rlRule.Key = defaultKey
135					if rule.Key != "" {
136						rlRule.Key = rule.Key
137					}
138	
139					rlRule.ZoneName = fmt.Sprintf("%s_rl_%s_rule%d", rlp.Namespace, rlp.Name, i)
140	
141					settings.Rule = append(settings.Rule, rlRule)
142				}
143			}
144		}
145	
146		return settings
147	}
148	
149	// Generator generates nginx configuration based on a rate limit policy.
150	type Generator struct {
151		policies.UnimplementedGenerator
152	}
153	
154	// NewGenerator returns a new instance of Generator.
155	func NewGenerator() *Generator {
156		return &Generator{}
157	}
158	
159	// GenerateForHTTP generates policy configuration for the http block.
160	func (g Generator) GenerateForHTTP(pols []policies.Policy) policies.GenerateResultFiles {
161		return generate(pols, tmplHTTP)
162	}
163	
164	// GenerateForServer generates policy configuration for the server block.
165	func (g Generator) GenerateForServer(pols []policies.Policy, _ http.Server) policies.GenerateResultFiles {
166		return generate(pols, tmplServer)
167	}
168	
169	// GenerateForLocation generates policy configuration for a normal location block.
170	func (g Generator) GenerateForLocation(pols []policies.Policy, _ http.Location) policies.GenerateResultFiles {
171		return generate(pols, tmplLocation)
172	}
173	
174	func generate(pols []policies.Policy, tmpl *template.Template) policies.GenerateResultFiles {
175		files := make(policies.GenerateResultFiles, 0, len(pols))
176	
177		for _, pol := range pols {
178			rlp, ok := pol.(*ngfAPI.RateLimitPolicy)
179			if !ok {
180				continue
181			}
182	
183			isHTTPContextOnly := isShadowPolicy(rlp)
184	
185			// Route-attached policies generate limit_req_zone at the http context via an internally-created
186			// copy (marked with the http-context-only annotation). That copy should never generate limit_req
187			// at the server level doing so would incorrectly rate limit all routes on the server, and the block
188			// could possibly have its own limit_req directives.
189			if tmpl == tmplServer && isHTTPContextOnly {
190				continue
191			}
192	
193			settings := getRateLimitSettings(*rlp)
194	
195			var suffix string
196			switch tmpl {
197			case tmplHTTP:
198				if isHTTPContextOnly {
199					suffix = fileNameSuffixHTTP
200				} else {
201					suffix = fileNameSuffixGateway
202				}
203			case tmplServer:
204				suffix = fileNameSuffixServer
205			case tmplLocation:
206				suffix = fileNameSuffixLocation
207			}
208	
209			name := fmt.Sprintf("%s_%s_%s_%s.conf", fileNamePrefix, rlp.Namespace, rlp.Name, suffix)
210	
211			files = append(files, policies.File{
212				Name:    name,
213				Content: helpers.MustExecuteTemplate(tmpl, settings),
214			})
215		}
216	
217		return files
218	}
219	
220	// isShadowPolicy checks if a RateLimitPolicy is intended to
221	// generate configuration only for the http context by looking for a specific annotation.
222	func isShadowPolicy(rlp *ngfAPI.RateLimitPolicy) bool {
223		if rlp.Annotations == nil {
224			return false
225		}
226		val, exists := rlp.Annotations[dataplane.InternalRLPAnnotationKey]
227		return exists && val == dataplane.InternalRLPAnnotationValue
228	}
