1	package clientsettings
2	
3	import (
4		"k8s.io/apimachinery/pkg/util/validation/field"
5		gatewayv1 "sigs.k8s.io/gateway-api/apis/v1"
6	
7		ngfAPI "github.com/nginx/nginx-gateway-fabric/v2/apis/v1alpha1"
8		"github.com/nginx/nginx-gateway-fabric/v2/internal/controller/nginx/config/policies"
9		"github.com/nginx/nginx-gateway-fabric/v2/internal/controller/state/conditions"
10		"github.com/nginx/nginx-gateway-fabric/v2/internal/controller/state/validation"
11		"github.com/nginx/nginx-gateway-fabric/v2/internal/framework/helpers"
12		"github.com/nginx/nginx-gateway-fabric/v2/internal/framework/kinds"
13	)
14	
15	// Validator validates a ClientSettingsPolicy.
16	// Implements policies.Validator interface.
17	type Validator struct {
18		genericValidator validation.GenericValidator
19	}
20	
21	// NewValidator returns a new instance of Validator.
22	func NewValidator(genericValidator validation.GenericValidator) *Validator {
23		return &Validator{genericValidator: genericValidator}
24	}
25	
26	// Validate validates the spec of a ClientSettingsPolicy.
27	func (v *Validator) Validate(policy policies.Policy) []conditions.Condition {
28		csp := helpers.MustCastObject[*ngfAPI.ClientSettingsPolicy](policy)
29	
30		targetRefPath := field.NewPath("spec").Child("targetRef")
31		supportedKinds := []gatewayv1.Kind{kinds.Gateway, kinds.HTTPRoute, kinds.GRPCRoute}
32		supportedGroups := []gatewayv1.Group{gatewayv1.GroupName}
33	
34		if err := policies.ValidateTargetRef(csp.Spec.TargetRef, targetRefPath, supportedGroups, supportedKinds); err != nil {
35			return []conditions.Condition{conditions.NewPolicyInvalid(err.Error())}
36		}
37	
38		if err := v.validateSettings(csp.Spec); err != nil {
39			return []conditions.Condition{conditions.NewPolicyInvalid(err.Error())}
40		}
41	
42		return nil
43	}
44	
45	// ValidateGlobalSettings validates a ClientSettingsPolicy with respect to the NginxProxy global settings.
46	func (v *Validator) ValidateGlobalSettings(
47		_ policies.Policy,
48		_ *policies.GlobalSettings,
49	) []conditions.Condition {
50		return nil
51	}
52	
53	// Conflicts returns true if the two ClientSettingsPolicies conflict.
54	func (v *Validator) Conflicts(polA, polB policies.Policy) bool {
55		cspA := helpers.MustCastObject[*ngfAPI.ClientSettingsPolicy](polA)
56		cspB := helpers.MustCastObject[*ngfAPI.ClientSettingsPolicy](polB)
57	
58		return conflicts(cspA.Spec, cspB.Spec)
59	}
60	
61	func conflicts(a, b ngfAPI.ClientSettingsPolicySpec) bool {
62		if a.Body != nil && b.Body != nil && bodyConflicts(*a.Body, *b.Body) {
63			return true
64		}
65	
66		if a.KeepAlive != nil && b.KeepAlive != nil && keepAliveConflicts(*a.KeepAlive, *b.KeepAlive) {
67			return true
68		}
69	
70		return false
71	}
72	
73	func bodyConflicts(a, b ngfAPI.ClientBody) bool {
74		return (a.Timeout != nil && b.Timeout != nil) || (a.MaxSize != nil && b.MaxSize != nil)
75	}
76	
77	func keepAliveConflicts(a, b ngfAPI.ClientKeepAlive) bool {
78		return (a.Requests != nil && b.Requests != nil) ||
79			(a.Time != nil && b.Time != nil) ||
80			(a.MinTimeout != nil && b.MinTimeout != nil) ||
81			(a.Timeout != nil && b.Timeout != nil)
82	}
83	
84	// validateSettings performs validation on fields in the spec that are vulnerable to code injection.
85	// For all other fields, we rely on the CRD validation.
86	func (v *Validator) validateSettings(spec ngfAPI.ClientSettingsPolicySpec) error {
87		var allErrs field.ErrorList
88		fieldPath := field.NewPath("spec")
89	
90		if spec.Body != nil {
91			allErrs = append(allErrs, v.validateClientBody(*spec.Body, fieldPath.Child("body"))...)
92		}
93	
94		if spec.KeepAlive != nil {
95			allErrs = append(allErrs, v.validateClientKeepAlive(*spec.KeepAlive, fieldPath.Child("keepAlive"))...)
96		}
97	
98		return allErrs.ToAggregate()
