12	)
13	
14	var (
15		tmpl            = template.Must(template.New("observability policy").Parse(observabilityTemplate))
16		tmplInternal    = template.Must(template.New("observability policy internal").Parse(internalTemplate))
17		tmplExtRedirect = template.Must(template.New("observability policy ext redirect").Parse(externalRedirectTemplate))
18	)
19	
20	const observabilityTemplate = `
21	{{- if .Tracing }}
22	otel_trace {{ .Strategy }};
23	  {{- if .Tracing.Context }}
24	otel_trace_context {{ .Tracing.Context }};
25	  {{- end }}
26	  {{- if .Tracing.SpanName }}
27	otel_span_name "{{ .Tracing.SpanName }}";
28	  {{- end }}
29	  {{- range $attr := .Tracing.SpanAttributes }}
30	otel_span_attr "{{ $attr.Key }}" "{{ $attr.Value }}";
31	  {{- end }}
32	  {{- range $attr := .GlobalSpanAttributes }}
33	otel_span_attr "{{ $attr.Key }}" "{{ $attr.Value }}";
34	  {{- end }}
35	{{- end }}
36	`
37	
38	const internalTemplate = `
39	{{- if .Tracing }}
40	  {{- if .Tracing.SpanName }}
41	otel_span_name "{{ .Tracing.SpanName }}";
42	  {{- else }}
43	otel_span_name $request_uri_path;
44	  {{- end }}
45	  {{- range $attr := .Tracing.SpanAttributes }}
46	otel_span_attr "{{ $attr.Key }}" "{{ $attr.Value }}";
47	  {{- end }}
48	  {{- range $attr := .GlobalSpanAttributes }}
49	otel_span_attr "{{ $attr.Key }}" "{{ $attr.Value }}";
50	  {{- end }}
51	{{- end }}
52	`
53	
54	const externalRedirectTemplate = `
55	{{- if .Tracing }}
56	otel_trace {{ .Strategy }};
57	  {{- if .Tracing.Context }}
58	otel_trace_context {{ .Tracing.Context }};
59	  {{- end }}
60	{{- end }}
61	`
62	
63	// Generator generates nginx configuration based on an observability policy.
64	type Generator struct {
65		policies.UnimplementedGenerator
66	
67		telemetryConf dataplane.Telemetry
68	}
69	
70	// NewGenerator returns a new instance of Generator.
71	func NewGenerator(telemetry dataplane.Telemetry) *Generator {
72		return &Generator{telemetryConf: telemetry}
73	}
74	
75	// GenerateForLocation generates policy configuration for a normal location block.
76	// For a normal location, all directives are applied.
77	// When the configuration involves a normal location redirecting to an internal location,
78	// only otel_trace and otel_trace_context are applied to the normal location.
79	func (g Generator) GenerateForLocation(pols []policies.Policy, location http.Location) policies.GenerateResultFiles {
80		buildTemplate := func(
81			tmplate *template.Template,
82			fileSuffix string,
83			includeGlobalAttrs bool,
84		) policies.GenerateResultFiles {
85			for _, pol := range pols {
86				obs, ok := pol.(*ngfAPIv1alpha2.ObservabilityPolicy)
87				if !ok {
88					continue
89				}
90	
91				fields := map[string]any{
92					"Tracing":  obs.Spec.Tracing,
93					"Strategy": getStrategy(obs),
94				}
95				if includeGlobalAttrs {
96					fields["GlobalSpanAttributes"] = g.telemetryConf.SpanAttributes
97				}
98	
99				return policies.GenerateResultFiles{
100					{
101						Name:    fmt.Sprintf("ObservabilityPolicy_%s_%s_%s.conf", obs.Namespace, obs.Name, fileSuffix),
102						Content: helpers.MustExecuteTemplate(tmplate, fields),
103					},
104				}
105			}
106			return nil
107		}
108	
109		if location.Type == http.ExternalLocationType {
110			return buildTemplate(tmpl, "ext", true)
111		}
112	
113		return buildTemplate(tmplExtRedirect, "redirect", false)
114	}
115	
116	// GenerateForInternalLocation generates policy configuration for an internal location block.
117	// otel_span_attr and otel_span_name are set in the internal location, with otel_trace and otel_trace_context
118	// being specified in the external location that redirects to the internal location.
119	func (g Generator) GenerateForInternalLocation(pols []policies.Policy) policies.GenerateResultFiles {
120		for _, pol := range pols {
121			obs, ok := pol.(*ngfAPIv1alpha2.ObservabilityPolicy)
122			if !ok {
123				continue
124			}
125	
126			fields := map[string]any{
127				"Tracing":              obs.Spec.Tracing,
128				"GlobalSpanAttributes": g.telemetryConf.SpanAttributes,
129			}
130	
131			return policies.GenerateResultFiles{
132				{
133					Name:    fmt.Sprintf("ObservabilityPolicy_%s_%s_int.conf", obs.Namespace, obs.Name),
134					Content: helpers.MustExecuteTemplate(tmplInternal, fields),
135				},
136			}
137		}
138	
139		return nil
140	}
141	
142	func getStrategy(obs *ngfAPIv1alpha2.ObservabilityPolicy) string {
143		var strategy string
144		if obs.Spec.Tracing != nil {
145			switch obs.Spec.Tracing.Strategy {
146			case ngfAPIv1alpha2.TraceStrategyParent:
147				strategy = "$otel_parent_sampled"
148			case ngfAPIv1alpha2.TraceStrategyRatio:
149				strategy = "on"
150				if obs.Spec.Tracing.Ratio != nil {
151					if *obs.Spec.Tracing.Ratio > 0 {
152						strategy = dataplane.CreateRatioVarName(*obs.Spec.Tracing.Ratio)
153					} else {
154						strategy = "off"
155					}
156				}
157			default:
158				strategy = "off"
159			}
160		}
161	
162		return strategy
163	}
