	ngfAPIv1alpha2 "github.com/nginx/nginx-gateway-fabric/v2/apis/v1alpha2"
	"github.com/nginx/nginx-gateway-fabric/v2/internal/controller/nginx/config/http"
	"github.com/nginx/nginx-gateway-fabric/v2/internal/controller/nginx/config/policies"
	"github.com/nginx/nginx-gateway-fabric/v2/internal/controller/state/dataplane"
	"github.com/nginx/nginx-gateway-fabric/v2/internal/framework/helpers"
)

var (
	tmpl            = template.Must(template.New("observability policy").Parse(observabilityTemplate))
	tmplInternal    = template.Must(template.New("observability policy internal").Parse(internalTemplate))
	tmplExtRedirect = template.Must(template.New("observability policy ext redirect").Parse(externalRedirectTemplate))
)

const observabilityTemplate = `
{{- if .Tracing }}
otel_trace {{ .Strategy }};
  {{- if .Tracing.Context }}
otel_trace_context {{ .Tracing.Context }};
  {{- end }}
  {{- if .Tracing.SpanName }}
otel_span_name "{{ .Tracing.SpanName }}";
  {{- end }}
  {{- range $attr := .Tracing.SpanAttributes }}
otel_span_attr "{{ $attr.Key }}" "{{ $attr.Value }}";
  {{- end }}
  {{- range $attr := .GlobalSpanAttributes }}
otel_span_attr "{{ $attr.Key }}" "{{ $attr.Value }}";
  {{- end }}
{{- end }}
`

const internalTemplate = `
{{- if .Tracing }}
  {{- if .Tracing.SpanName }}
otel_span_name "{{ .Tracing.SpanName }}";
  {{- else }}
otel_span_name $request_uri_path;
  {{- end }}
  {{- range $attr := .Tracing.SpanAttributes }}
otel_span_attr "{{ $attr.Key }}" "{{ $attr.Value }}";
  {{- end }}
  {{- range $attr := .GlobalSpanAttributes }}
otel_span_attr "{{ $attr.Key }}" "{{ $attr.Value }}";
  {{- end }}
{{- end }}
`

const externalRedirectTemplate = `
{{- if .Tracing }}
otel_trace {{ .Strategy }};
  {{- if .Tracing.Context }}
otel_trace_context {{ .Tracing.Context }};
  {{- end }}
{{- end }}
`

// Generator generates nginx configuration based on an observability policy.
type Generator struct {
	policies.UnimplementedGenerator

	telemetryConf dataplane.Telemetry
}

// NewGenerator returns a new instance of Generator.
func NewGenerator(telemetry dataplane.Telemetry) *Generator {
	return &Generator{telemetryConf: telemetry}
}

// GenerateForLocation generates policy configuration for a normal location block.
// For a normal location, all directives are applied.
// When the configuration involves a normal location redirecting to an internal location,
// only otel_trace and otel_trace_context are applied to the normal location.
func (g Generator) GenerateForLocation(pols []policies.Policy, location http.Location) policies.GenerateResultFiles {
	buildTemplate := func(
		tmplate *template.Template,
		fileSuffix string,
		includeGlobalAttrs bool,
	) policies.GenerateResultFiles {
		for _, pol := range pols {
			obs, ok := pol.(*ngfAPIv1alpha2.ObservabilityPolicy)
			if !ok {
				continue
			}

			fields := map[string]any{
				"Tracing":  obs.Spec.Tracing,
				"Strategy": getStrategy(obs),
			}
			if includeGlobalAttrs {
				fields["GlobalSpanAttributes"] = g.telemetryConf.SpanAttributes
			}

			return policies.GenerateResultFiles{
				{
					Name:    fmt.Sprintf("ObservabilityPolicy_%s_%s_%s.conf", obs.Namespace, obs.Name, fileSuffix),
					Content: helpers.MustExecuteTemplate(tmplate, fields),
				},
			}
		}
		return nil
	}

	if location.Type == http.ExternalLocationType {
		return buildTemplate(tmpl, "ext", true)
	}

	return buildTemplate(tmplExtRedirect, "redirect", false)
}

// GenerateForInternalLocation generates policy configuration for an internal location block.
// otel_span_attr and otel_span_name are set in the internal location, with otel_trace and otel_trace_context
// being specified in the external location that redirects to the internal location.
func (g Generator) GenerateForInternalLocation(pols []policies.Policy) policies.GenerateResultFiles {
	for _, pol := range pols {
		obs, ok := pol.(*ngfAPIv1alpha2.ObservabilityPolicy)
		if !ok {
			continue
		}

		fields := map[string]any{
			"Tracing":              obs.Spec.Tracing,
			"GlobalSpanAttributes": g.telemetryConf.SpanAttributes,
		}

		return policies.GenerateResultFiles{
			{
				Name:    fmt.Sprintf("ObservabilityPolicy_%s_%s_int.conf", obs.Namespace, obs.Name),
				Content: helpers.MustExecuteTemplate(tmplInternal, fields),
			},
		}
	}

	return nil
}

func getStrategy(obs *ngfAPIv1alpha2.ObservabilityPolicy) string {
	var strategy string
	if obs.Spec.Tracing != nil {
		switch obs.Spec.Tracing.Strategy {
		case ngfAPIv1alpha2.TraceStrategyParent:
			strategy = "$otel_parent_sampled"
		case ngfAPIv1alpha2.TraceStrategyRatio:
			strategy = "on"
			if obs.Spec.Tracing.Ratio != nil {
				if *obs.Spec.Tracing.Ratio > 0 {
					strategy = dataplane.CreateRatioVarName(*obs.Spec.Tracing.Ratio)
				} else {
					strategy = "off"
				}
			}
		default:
			strategy = "off"
		}
	}

	return strategy
}

package snippetspolicy

import (
	"fmt"

	"github.com/nginx/nginx-gateway-fabric/v2/apis/v1alpha1"
	"github.com/nginx/nginx-gateway-fabric/v2/internal/controller/nginx/config/http"
	"github.com/nginx/nginx-gateway-fabric/v2/internal/controller/nginx/config/policies"
)

const (
	mainTemplate = `
# SnippetsPolicy %s main context
%s
`
	httpTemplate = `
# SnippetsPolicy %s http context
%s
`
	serverTemplate = `
# SnippetsPolicy %s server context
%s
`
	locationTemplate = `
# SnippetsPolicy %s location context
%s
`
)

// Generator generates NGINX configuration snippets for SnippetsPolicies.
type Generator struct {
	policies.UnimplementedGenerator
}

// NewGenerator returns a new instance of Generator.
func NewGenerator() *Generator {
	return &Generator{}
}

// GenerateForMain generates policy configuration for the main block.
func (g *Generator) GenerateForMain(pols []policies.Policy) policies.GenerateResultFiles {
	return g.generate(pols, v1alpha1.NginxContextMain)
}

// GenerateForHTTP generates policy configuration for the http block.
func (g *Generator) GenerateForHTTP(pols []policies.Policy) policies.GenerateResultFiles {
	return g.generate(pols, v1alpha1.NginxContextHTTP)
}

// GenerateForServer generates policy configuration for the server block.
func (g *Generator) GenerateForServer(pols []policies.Policy, _ http.Server) policies.GenerateResultFiles {
	return g.generate(pols, v1alpha1.NginxContextHTTPServer)
}

// GenerateForLocation generates policy configuration for the location block.
func (g *Generator) GenerateForLocation(pols []policies.Policy, _ http.Location) policies.GenerateResultFiles {
	return g.generate(pols, v1alpha1.NginxContextHTTPServerLocation)
}

// GenerateForInternalLocation generates policy configuration for an internal location block.
func (g *Generator) GenerateForInternalLocation(pols []policies.Policy) policies.GenerateResultFiles {
	return g.generate(pols, v1alpha1.NginxContextHTTPServerLocation)
}

func (g *Generator) generate(
	pols []policies.Policy,
	context v1alpha1.NginxContext,
) policies.GenerateResultFiles {
	var files policies.GenerateResultFiles

	for _, policy := range pols {
		sp, ok := policy.(*v1alpha1.SnippetsPolicy)
		if !ok {
			continue
		}

		for _, snippet := range sp.Spec.Snippets {
			if snippet.Context != context {
				continue
			}

			policyNsName := fmt.Sprintf("%s/%s", sp.GetNamespace(), sp.GetName())
			policyFileID := fmt.Sprintf("%s-%s", sp.GetNamespace(), sp.GetName())

			// Build content and filename
			var content string
			var filename string

			switch context {
			case v1alpha1.NginxContextMain:
				content = fmt.Sprintf(mainTemplate, policyNsName, snippet.Value)
				filename = fmt.Sprintf("SnippetsPolicy_main_%s.conf", policyFileID)
			case v1alpha1.NginxContextHTTP:
				content = fmt.Sprintf(httpTemplate, policyNsName, snippet.Value)
				filename = fmt.Sprintf("SnippetsPolicy_http_%s.conf", policyFileID)
			case v1alpha1.NginxContextHTTPServer:
				content = fmt.Sprintf(serverTemplate, policyNsName, snippet.Value)
				filename = fmt.Sprintf("SnippetsPolicy_server_%s.conf", policyFileID)
			case v1alpha1.NginxContextHTTPServerLocation:
				content = fmt.Sprintf(locationTemplate, policyNsName, snippet.Value)
				filename = fmt.Sprintf("SnippetsPolicy_location_%s.conf", policyFileID)
			}

			files = append(files, policies.File{
				Name:    filename,
				Content: []byte(content),
			})
		}
	}
	return files
}

